// Verifies the Stripe webhook signature using the raw request body.
// Stripe-Signature header format: t=<timestamp>,v1=<signature>
// Set STRIPE_WEBHOOK_SECRET as an n8n environment variable (Settings > Environment).
const crypto = require('crypto');

const sigHeader = $input.first().json.headers['stripe-signature'];
const rawBody = $input.first().json.rawBody ? $input.first().json.rawBody.toString('utf8') : null;
const secret = $env.STRIPE_WEBHOOK_SECRET;

if (!sigHeader || !rawBody || !secret) {
  throw new Error('Missing signature header, raw body, or STRIPE_WEBHOOK_SECRET env var.');
}

const parts = Object.fromEntries(sigHeader.split(',').map(p => p.split('=')));
const timestamp = parts.t;
const signature = parts.v1;

if (!timestamp || !signature) {
  throw new Error('Malformed Stripe-Signature header.');
}

const signedPayload = `${timestamp}.${rawBody}`;
const expected = crypto.createHmac('sha256', secret).update(signedPayload, 'utf8').digest('hex');

const expectedBuf = Buffer.from(expected, 'hex');
const signatureBuf = Buffer.from(signature, 'hex');
const valid = expectedBuf.length === signatureBuf.length && crypto.timingSafeEqual(expectedBuf, signatureBuf);

// Reject requests older than 5 minutes to guard against replay.
const age = Math.abs(Date.now() / 1000 - Number(timestamp));
if (!valid || age > 300) {
  throw new Error('Stripe signature verification failed.');
}

const event = JSON.parse(rawBody);
return [{ json: event }];

// Builds the signed download link — must match src/app/api/download/route.ts exactly:
// HMAC-SHA256(DELIVERY_LINK_SECRET, `${product}.${expires}`), hex digest.
// Set DELIVERY_LINK_SECRET as an n8n environment variable to the SAME value
// that was added to Vercel (production + preview) for stitch-hospitality-site.
const crypto = require('crypto');

const product = 'full-os';
const secret = $env.DELIVERY_LINK_SECRET;
if (!secret) throw new Error('DELIVERY_LINK_SECRET env var is not set in n8n.');

const expires = Date.now() + 7 * 24 * 60 * 60 * 1000; // 7-day link validity
const token = crypto.createHmac('sha256', secret).update(`${product}.${expires}`).digest('hex');
const downloadUrl = `https://www.stitchhospitality.com/api/download?product=${product}&expires=${expires}&token=${token}`;

const event = $input.first().json;
return [{
  json: {
    productName: 'The GM Ownership Report OS — Full OS',
    customerEmail: event.data.object.customer_details?.email,
    downloadUrl,
  },
}];

// Same signing pattern as the Full OS branch, product = 'playbook'.
const crypto = require('crypto');

const product = 'playbook';
const secret = $env.DELIVERY_LINK_SECRET;
if (!secret) throw new Error('DELIVERY_LINK_SECRET env var is not set in n8n.');

const expires = Date.now() + 7 * 24 * 60 * 60 * 1000;
const token = crypto.createHmac('sha256', secret).update(`${product}.${expires}`).digest('hex');
const downloadUrl = `https://www.stitchhospitality.com/api/download?product=${product}&expires=${expires}&token=${token}`;

const event = $input.first().json;
return [{
  json: {
    productName: 'The GM Ownership Report OS — PDF Playbook',
    customerEmail: event.data.object.customer_details?.email,
    downloadUrl,
  },
}];

